                    let needs_jump = !prefer_public && nodes_with_ips.iter().any(|(_, _, pp)| *pp);
                    let result = if needs_jump {
                        ssh_run_jump(
                            &primary_cp_ip,
                            ssh_user,
                            ip,
                            ssh_user,
                            &ssh_priv_path,
                            "sudo reboot",
                        )
                    } else {
                        ssh_run(ip, ssh_user, &ssh_priv_path, "sudo reboot")
                    };
                    // Convert error to a Send-safe string
                    (name.clone(), result.map_err(|e| e.to_string()))
                })
            })
